    // Helper function to check if required_segment is a cyclic shift of block
    // Both segments must have length k.
    let check_cyclic_shift = |block: &[i64], required_segment: &[i64]| -> bool {
        let k = block.len();
        if k == 0 {
            return true;
        }
        if block.len() != required_segment.len() {
            return false;
        }

        // Check all k possible rotations of block
        for r in 0..k {
            let mut matches = true;
            for j in 0..k {
                // Element at index j of the rotated block: block[(j + r) % k]
                // Compare with required_segment[j]
                if block[(j + r) % k] != required_segment[j] {
                    matches = false;
                    break;
                }
            }
            if matches {
                return true;
            }
        }
        false
    };

    // 1. Find all divisors of n
    let mut divisors = Vec::new();
    let mut i = 1;
    while i * i <= n {
        if n % i == 0 {
            divisors.push(i as i64);
            if i * i != n {
                divisors.push(n / i as i64);
            }
        }
        i += 1;
    }
    divisors.sort_unstable();

    let mut sum_of_valid_k = 0;

    // 2. Check each divisor k
    for &k_i64 in &divisors {
        let k = k_i64 as usize;

        // If k=1, the condition implies it fails if n > 1, based on examples.
        if k == 1 && n > 1 {
            continue;
        }

        let mut is_k_valid = true;

        // Divide nums into k-length contiguous subarrays (blocks)
        let num_blocks = n / k;

        for i_block in 0..num_blocks {
            let start = i_block * k;

            // The current block from nums
            let block = &nums[start..(start + k)];

            // The required segment from sorted_nums
            let required_segment = &sorted_nums[start..(start + k)];

            // Check if 'required_segment' is a cyclic shift of 'block'
            if !check_cyclic_shift(block, required_segment) {
                is_k_valid = false;
                break;
            }
        }

        if is_k_valid {
            sum_of_valid_k += k_i64;
        }
    }

    sum_of_valid_k
}
